---
import type { HTMLAttributes } from "astro/types"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

type Props = HTMLAttributes<"section"> & VariantProps<typeof variants>

const variants = cva(
  "relative flex scroll-mt-12 flex-col gap-16 py-24 lg:scroll-mt-16 lg:py-32",
  {
    variants: {
      variant: {
        default: "bg-background w-full",
        floating:
          "bg-background max-w-container mx-auto my-12 w-[calc(100%-3rem)] overflow-hidden rounded-xl border shadow-md lg:my-16",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

const { class: className, variant, ...props } = Astro.props
---

<section
  class={cn(variants({ variant }), className)}
  data-slot="section"
  data-variant={variant}
  {...props}
>
  <slot />
</section>
